import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

/**
 * Tests for the fix of the issue where double KDoc comments caused spurious lint violations.
 * See: https://github.com/pinterest/ktlint/issues/1867
 */
class SpacingBetweenDeclarationsWithAnnotationsRuleDoubleKdocTest {
    private val spacingBetweenDeclarationsWithAnnotationsRuleAssertThat =
        assertThatRule { SpacingBetweenDeclarationsWithAnnotationsRule() }

    @Test
    fun `Given a double KDoc before an annotated declaration with a blank line before the first KDoc should not report a violation`() {
        val code =
            """
            public class JsonReader {
                public var lenient: Boolean = false

                /**
                 * Hey
                 */
                /** Sup */
                @get:JvmName("failOnUnknown")
                public var failOnUnknown: Boolean = false
            }
            """.trimIndent()
        spacingBetweenDeclarationsWithAnnotationsRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a double KDoc before an annotated declaration without a blank line should report a violation and fix correctly`() {
        val code =
            """
            public class JsonReader {
                public var lenient: Boolean = false
                /**
                 * Hey
                 */
                /** Sup */
                @get:JvmName("failOnUnknown")
                public var failOnUnknown: Boolean = false
            }
            """.trimIndent()
        val formattedCode =
            """
            public class JsonReader {
                public var lenient: Boolean = false

                /**
                 * Hey
                 */
                /** Sup */
                @get:JvmName("failOnUnknown")
                public var failOnUnknown: Boolean = false
            }
            """.trimIndent()
        spacingBetweenDeclarationsWithAnnotationsRuleAssertThat(code)
            .hasLintViolation(7, 5, "Declarations and declarations with annotations should have an empty space between.")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a single KDoc before an annotated declaration with a blank line should not report a violation`() {
        val code =
            """
            public class JsonReader {
                public var lenient: Boolean = false

                /**
                 * Hey
                 */
                @get:JvmName("failOnUnknown")
                public var failOnUnknown: Boolean = false
            }
            """.trimIndent()
        spacingBetweenDeclarationsWithAnnotationsRuleAssertThat(code).hasNoLintViolations()
    }

